<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Session.php'; require_once __DIR__.'/../includes/Auth.php'; Session::start(); if(Auth::check()){header('Location: /admin/');exit;} $error='';$redirect=$_GET['redirect']??'/admin/'; if($_SERVER['REQUEST_METHOD']==='POST'){if(!Auth::validateCsrf())$error='安全验证失败，请重试。';elseif(!Auth::rateLimitCheck('login'))$error='登录尝试过于频繁。';else{$u=trim($_POST['username']??'');$p=$_POST['password']??'';if(empty($u)||empty($p))$error='请输入用户名和密码。';elseif(Auth::login($u,$p)){header('Location: '.$redirect);exit;}else $error='用户名或密码错误。';}} $csrf=Auth::csrfToken(); ?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>登录 - <?php echo APP_NAME;?></title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:'Inter',sans-serif;background:linear-gradient(135deg,#667eea,#764ba2);min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px}.box{background:#fff;border-radius:16px;box-shadow:0 20px 60px rgba(0,0,0,.15);padding:40px;width:100%;max-width:420px}.box h1{font-size:1.5rem;text-align:center;margin-bottom:8px;color:#333}.sub{text-align:center;color:#888;font-size:.875rem;margin-bottom:32px}.fg{margin-bottom:20px}.fg label{display:block;font-size:.875rem;font-weight:500;color:#555;margin-bottom:6px}.fg input{width:100%;padding:12px 16px;border:2px solid #e5e7eb;border-radius:10px;font-size:1rem;outline:none}.fg input:focus{border-color:#667eea}.btn{width:100%;padding:14px;background:linear-gradient(135deg,#667eea,#764ba2);color:#fff;border:none;border-radius:10px;font-size:1rem;font-weight:600;cursor:pointer}.btn:hover{opacity:.9}.err{background:#fef2f2;color:#dc2626;padding:12px 16px;border-radius:8px;font-size:.875rem;margin-bottom:20px}.back{display:block;text-align:center;margin-top:20px;color:#888;font-size:.875rem;text-decoration:none}</style></head><body><div class="box"><h1><?php echo APP_NAME;?></h1><p class="sub">管理后台登录</p><?php if($error):?><div class="err"><?php echo e($error);?></div><?php endif;?><form method="POST"><input type="hidden" name="csrf_token" value="<?php echo e($csrf);?>"><div class="fg"><label>用户名</label><input type="text" name="username" required autocomplete="username" autofocus></div><div class="fg"><label>密码</label><input type="password" name="password" required autocomplete="current-password"></div><button type="submit" class="btn">登 录</button></form><a href="/" class="back">&larr; 返回状态页面</a></div></body></html>